// // This module implements a 5-bit wide, 2-to-1 demultiplexer. When the select signal is low, the output will be equal to input1; when the select signal is high, the output will reflect input0.
module top_module(out,input0,input1,select);input [4:0] input0,input1;

input select;

 output [4:0] out;

assign out = (select==1'b1) ? input1:input0;

endmodule
